import axios from 'axios';

const API = axios.create({
  baseURL: 'http://localhost:8000/api',
});

// Auth
export const loginAdmin = (username, password) => {
  return API.post(`/login?username=${username}&password=${password}`);
};

// Jobs
export const getJobs = () => API.get('/jobs');
export const createJob = (title, description, required_skills, required_experience, required_education) => {
  return API.post(`/jobs?title=${title}&description=${description}&required_skills=${required_skills}&required_experience=${required_experience}&required_education=${required_education}`);
};

// Upload
export const uploadResumes = (jobId, files) => {
  const formData = new FormData();
  formData.append('job_id', jobId);
  files.forEach(file => formData.append('files', file));
  return API.post('/upload-resumes', formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  });
};

// Rankings
export const getRankings = (jobId) => API.get(`/rankings/${jobId}`);
